import streamlit as st 
st.title("chai taste poll")

col1 , col2 = st.columns(2)
with col1 :
    st.header("masala chai")
    
    vote1 = st.button("VOTE MASALA CHAI")
    st.image("data:image/jpeg;base64,", width=100)
with col2 : 
    st.header("adarak chai")
    st.image("https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcSTVOljzmVZ4_oc3oVBPaNjqbvX-oGVTkt_UA&s", width=100)
    vote2 = st.button("VOTE ADARAK CHAI")
  
if vote1:
    st.success("thanks for voting masala chai ")
elif vote2:
    st.success("thanks for voting adrak chai") 
    
name =st.sidebar.text_input("enter your name")
tea = st.sidebar.selectbox("choose your chai", [ "masala chai ", " adarak chai"])

st.write(f"Welcome {name} and your {tea} chai is getting ready")

with st.expander("show chai making instruction"):
    st.write("""
             1. Boil water and tea leaves
             2. add milk and spices
             3. Server hot
             """)
st.markdown("### welcome to chai app")
st.markdown("> blockquote")

